"use client";

import {
  type ComponentProps,
  type MouseEvent,
  type PointerEvent,
  type ReactNode,
  type Ref,
  type RefObject,
  type SyntheticEvent,
  useCallback,
  useLayoutEffect,
  useRef,
  useState,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useFocusTrap } from "@/hooks/use-focus-trap";
import { usePresence } from "@/hooks/use-presence";
import { isHTMLDialogElement } from "@/lib/aria";

/** Props for dialog shell. */
export interface DialogShellProps extends ComponentProps<"dialog"> {
  /** Controlled open state. */
  open: boolean;
  /** Called when backdrop click occurs. */
  onBackdropClick?: (e: MouseEvent<HTMLDialogElement>) => void;
  /** Called when cancel occurs. */
  onCancel?: (e: SyntheticEvent<HTMLDialogElement>) => void;
  /** Called when before show modal occurs. */
  onBeforeShowModal?: (ownerDocument: Document) => void;
  /** Called when after show modal occurs. */
  onAfterShowModal?: () => void;
  /** Called after the exit transition has closed the native dialog. */
  onExitComplete?: () => void;
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Ref for the dialog element. */
  dialogRef?: Ref<HTMLDialogElement>;
  /** Element that receives focus when the overlay opens. */
  initialFocus?: RefObject<HTMLElement | null>;
}

// Per-document stacks of currently mounted, open DialogShell elements. Only the
// topmost shell in each document runs its focus trap so peer/stacked dialogs do
// not fight over focus via competing focusin listeners on ownerDocument.
// Subscribers are notified after every push/pop with the new top element for
// their document; each shell updates its local isTopShell state in response.
const openShellStacks = new WeakMap<Document, HTMLElement[]>();

interface ShellStackSubscriber {
  ownerDocument: Document;
  onTopChange: (top: HTMLElement | null) => void;
}

const shellStackSubscribers = new Set<ShellStackSubscriber>();

function getOpenShellStack(ownerDocument: Document): HTMLElement[] {
  let stack = openShellStacks.get(ownerDocument);
  if (!stack) {
    stack = [];
    openShellStacks.set(ownerDocument, stack);
  }
  return stack;
}

function notifyShellStack(ownerDocument: Document): void {
  const top = getOpenShellStack(ownerDocument).at(-1) ?? null;
  for (const subscriber of shellStackSubscribers) {
    if (subscriber.ownerDocument === ownerDocument) {
      subscriber.onTopChange(top);
    }
  }
}

function pushShell(element: HTMLElement): void {
  const ownerDocument = element.ownerDocument;
  getOpenShellStack(ownerDocument).push(element);
  notifyShellStack(ownerDocument);
}

function popShell(element: HTMLElement): void {
  const ownerDocument = element.ownerDocument;
  const stack = getOpenShellStack(ownerDocument);
  const index = stack.lastIndexOf(element);
  if (index >= 0) stack.splice(index, 1);
  notifyShellStack(ownerDocument);
}

function isEventOutsideDialogRect(
  event: { clientX: number; clientY: number },
  dialog: HTMLDialogElement,
): boolean {
  const rect = dialog.getBoundingClientRect();
  return (
    event.clientX < rect.left ||
    event.clientX > rect.right ||
    event.clientY < rect.top ||
    event.clientY > rect.bottom
  );
}

/** Renders the dialog shell component. */
export function DialogShell({
  open,
  onBackdropClick,
  onCancel,
  onBeforeShowModal,
  onAfterShowModal,
  onExitComplete,
  children,
  className,
  dialogRef: externalDialogRef,
  initialFocus,
  onClick,
  onClickCapture,
  onPointerDown,
  onAnimationEnd: externalOnAnimationEnd,
  ...props
}: DialogShellProps) {
  const shellRef = useRef<HTMLElement | null>(null);
  const didPressBackdropRef = useRef(false);
  const isClosingFromShellRef = useRef(false);
  // usePresence's native animationend/animationcancel listener owns the
  // exit-complete path; do not also wire the returned React handler here or
  // onExitComplete would fire twice on the non-portaled <dialog>.
  const { present } = usePresence({
    open,
    ref: shellRef,
    onExitComplete: () => {
      const element = shellRef.current;
      if (isHTMLDialogElement(element) && element.open) {
        isClosingFromShellRef.current = true;
        try {
          element.close();
        } finally {
          isClosingFromShellRef.current = false;
        }
      }
      onExitComplete?.();
    },
  });

  // DialogContent owns focus restoration via useFocusRestore, so this trap is
  // configured with restoreFocus: false.
  const trapActive = open && present;

  // When dialogs stack (peer Dialog defaultOpen or programmatically opened
  // dialog-in-dialog), only the topmost shell's trap stays enabled. Outer
  // traps go dormant so their ownerDocument-level focusin listeners do not
  // fight the inner trap. isTopShell defaults to false so the first-render
  // useFocusTrap effect is a no-op; the layout effect then pushes onto the
  // stack and notifies all subscribers, and the resulting setState triggers a
  // follow-up render where exactly one shell activates its trap.
  const [isTopShell, setIsTopShell] = useState(false);
  useLayoutEffect(() => {
    if (!trapActive) return;
    const element = shellRef.current;
    if (!element) return;
    const ownerDocument = element.ownerDocument;
    const subscriber: ShellStackSubscriber = {
      ownerDocument,
      onTopChange: (top) => setIsTopShell(top === element),
    };
    shellStackSubscribers.add(subscriber);
    pushShell(element);
    return () => {
      shellStackSubscribers.delete(subscriber);
      popShell(element);
      setIsTopShell(false);
    };
  }, [trapActive]);

  useFocusTrap(shellRef, { enabled: trapActive && isTopShell, restoreFocus: false, initialFocus });

  useLayoutEffect(() => {
    const element = shellRef.current;
    if (!isHTMLDialogElement(element)) return;
    if (open && present && !element.open) {
      onBeforeShowModal?.(element.ownerDocument);
      element.showModal();
      onAfterShowModal?.();
    }
  }, [onAfterShowModal, onBeforeShowModal, open, present]);

  useLayoutEffect(() => {
    const element = shellRef.current;
    if (!isHTMLDialogElement(element)) return;

    const handleNativeClose = () => {
      if (isClosingFromShellRef.current || !open || !present || element.open) return;
      onBeforeShowModal?.(element.ownerDocument);
      element.showModal();
      onAfterShowModal?.();
    };

    element.addEventListener("close", handleNativeClose);
    return () => element.removeEventListener("close", handleNativeClose);
  }, [onAfterShowModal, onBeforeShowModal, open, present]);

  const setShellRef = useCallback((node: HTMLElement | null) => {
    shellRef.current = node;
  }, []);
  const dialogRef: Ref<HTMLDialogElement> = useComposedRefs(
    setShellRef as Ref<HTMLElement>,
    externalDialogRef,
  );

  if (!present) return null;

  return (
    // biome-ignore lint/a11y/useKeyWithClickEvents: this onClick only detects backdrop (outside-rect) clicks to dismiss; keyboard dismissal is handled by the dialog's Escape behavior, so there is no keyboard equivalent for a backdrop click.
    <dialog
      {...props}
      ref={dialogRef}
      data-state={open ? "open" : "closed"}
      inert={open ? undefined : true}
      className={className}
      onClickCapture={(e) => {
        if (!open) {
          e.preventDefault();
          e.stopPropagation();
          return;
        }
        onClickCapture?.(e);
      }}
      onPointerDown={(e: PointerEvent<HTMLDialogElement>) => {
        onPointerDown?.(e);
        const element = shellRef.current;
        didPressBackdropRef.current =
          isHTMLDialogElement(element) &&
          e.target === element &&
          isEventOutsideDialogRect(e, element);
      }}
      onClick={(e: MouseEvent<HTMLDialogElement>) => {
        onClick?.(e);
        const element = shellRef.current;
        if (
          isHTMLDialogElement(element) &&
          didPressBackdropRef.current &&
          e.target === element &&
          isEventOutsideDialogRect(e, element)
        ) {
          onBackdropClick?.(e);
        }
        didPressBackdropRef.current = false;
      }}
      onCancel={(e) => {
        onCancel?.(e);
        e.preventDefault();
      }}
      onAnimationEnd={externalOnAnimationEnd}
    >
      {children}
    </dialog>
  );
}

@layer base {
  dialog {
    --dialog-duration: 0.15s;
    padding: 0;
    border: none;
    background: transparent;
    overflow: visible;
  }
}

@layer components {
  dialog::backdrop {
    background: var(--scrim);
    -webkit-backdrop-filter: blur(4px);
    backdrop-filter: blur(4px);
  }

  dialog[data-state="open"]::backdrop {
    animation: backdrop-in var(--dialog-duration) ease-out;
  }

  dialog[data-state="closed"]::backdrop {
    animation: backdrop-out var(--dialog-duration) ease-in forwards;
  }

  dialog[data-state="open"] {
    animation: dialog-in var(--dialog-duration) ease-out;
  }

  dialog[data-state="closed"] {
    animation: dialog-out var(--dialog-duration) ease-in forwards;
    pointer-events: none;
  }

  /*
   * Scroll lock contract.
   * Native <dialog>.showModal() does not lock body scroll on its own. This
   * CSS-only lock activates whenever any descendant <dialog> exposes the
   * [open] attribute, and unlocks once every dialog closes.
   * scrollbar-gutter: stable avoids a horizontal layout shift when the
   * scrollbar is hidden under hidden-overflow.
   *
   * Limits (consumers in these cases must opt into a JS lock):
   *   - Custom scroll roots: only the <body> is locked. Apps that scroll on
   *     <html>, a wrapping element, or a scroll container handle their own
   *     scroll lock.
   *   - iOS Safari rubber-band: overflow:hidden on body does not prevent
   *     touchmove from scrolling the visual viewport.
   *   - :has() support floor: Chrome 105+, Safari 15.4+, Firefox 121+ — older
   *     engines do not get any body lock.
   */
  body:has(dialog[open]) {
    overflow: hidden;
    scrollbar-gutter: stable;
  }
}

@keyframes dialog-in {
  from {
    opacity: 0;
    transform: scale(0.95);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes dialog-out {
  from {
    opacity: 1;
    transform: scale(1);
  }
  to {
    opacity: 0;
    transform: scale(0.95);
  }
}

@keyframes backdrop-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes backdrop-out {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

@media (prefers-reduced-motion: reduce) {
  dialog,
  dialog::backdrop {
    /* biome-ignore lint/complexity/noImportantStyles: prefers-reduced-motion override must defeat the dialog animation declarations regardless of specificity. */
    animation: none !important;
  }
}

/*
 * DialogContent corner accents. Four corners total: dialog::before/::after =
 * top corners, dialog > .dlg-corners::before/::after = bottom corners. The
 * .dlg-corners span is only rendered when corners !== "none" so the
 * default path stays a plain CSS rectangle.
 */
@layer components {
  /*
   * Default corner-token values are consumed via var() fallback at the corner
   * use sites below (not declared on the slot) so an ancestor-scoped override
   * reaches them. Defaults: --viewfinder-size → 18px; --viewfinder-weight → 2px;
   * --viewfinder-color → var(--foreground); --viewfinder-offset → 0px. The
   * per-corner variant overrides below still win.
   */
  [data-slot="dialog-content"][data-corners="subtle"] {
    --viewfinder-size: 12px;
    --viewfinder-weight: 1.5px;
    --viewfinder-color: var(--border);
  }

  [data-slot="dialog-content"][data-corners="bold"] {
    --viewfinder-size: 28px;
    --viewfinder-weight: 3px;
  }

  [data-slot="dialog-content"][data-corners="outset"] {
    --viewfinder-offset: -3px;
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::before,
  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::after,
  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::before,
  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::after {
    content: "";
    position: absolute;
    width: var(--viewfinder-size, 18px);
    height: var(--viewfinder-size, 18px);
    border: 0 solid var(--viewfinder-color, var(--foreground));
    pointer-events: none;
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::before {
    top: var(--viewfinder-offset, 0px);
    left: var(--viewfinder-offset, 0px);
    border-top-width: var(--viewfinder-weight, 2px);
    border-left-width: var(--viewfinder-weight, 2px);
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::after {
    top: var(--viewfinder-offset, 0px);
    right: var(--viewfinder-offset, 0px);
    border-top-width: var(--viewfinder-weight, 2px);
    border-right-width: var(--viewfinder-weight, 2px);
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::before {
    bottom: var(--viewfinder-offset, 0px);
    left: var(--viewfinder-offset, 0px);
    border-bottom-width: var(--viewfinder-weight, 2px);
    border-left-width: var(--viewfinder-weight, 2px);
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::after {
    bottom: var(--viewfinder-offset, 0px);
    right: var(--viewfinder-offset, 0px);
    border-bottom-width: var(--viewfinder-weight, 2px);
    border-right-width: var(--viewfinder-weight, 2px);
  }
}

/*
 * DialogTitle eyebrow meta tag typography tokens. Centralized here so consumers
 * can override the meta size/tracking globally without editing the primitive.
 */
@layer components {
  [data-slot="dialog-content"] {
    --dialog-title-meta-size: 11px;
    --dialog-title-meta-tracking: 0.08em;
  }
}

/*
 * Inset for the optional Dialog.CloseIcon (top-right). Default clears the
 * dialog edge; per-corner overrides push the button inward so it does not
 * collide with the corner accents.
 *   subtle  : 12px arms + 4px = 16px
 *   standard: 18px arms + 4px = 22px
 *   outset  : 18px arms (shifted -3px outside) + 4px ≈ 22px
 *   bold    : 28px arms + 4px = 32px
 */
@layer components {
  [data-slot="dialog-content"] {
    --dialog-close-btn-inset: 0.5rem;
  }

  [data-slot="dialog-content"][data-corners="subtle"] {
    --dialog-close-btn-inset: 16px;
  }

  [data-slot="dialog-content"][data-corners="standard"],
  [data-slot="dialog-content"][data-corners="outset"] {
    --dialog-close-btn-inset: 22px;
  }

  [data-slot="dialog-content"][data-corners="bold"] {
    --dialog-close-btn-inset: 32px;
  }
}
